module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [1:0] mul_en_out_reg = {mul_en_out_reg[0], mul_en_in};
assign mul_en_out = mul_en_out_reg[1];
reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_a_reg <= 8'd0;
        mul_b_reg <= 8'd0;
    end else begin
        if(mul_en_in == 1'b1) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end
end
wire [8:0] temp [7:0];
assign {temp[0][7], temp[0]} = {mul_b_reg[0]?mul_a_reg : 8'h0, 1'b0};
assign {temp[1][7], temp[1]} = {mul_b_reg[1]?{mul_a_reg[7], mul_a_reg} : 9'h0, 1'b0};
assign {temp[2][7], temp[2]} = {mul_b_reg[2]?{mul_a_reg[7:6], mul_a_reg[5:0]} : 10'h0, 1'b0};
assign {temp[3][7], temp[3]} = {mul_b_reg[3]?{mul_a_reg[7:5], mul_a_reg[4:0]} : 11'h0, 1'b0};
assign {temp[4][7], temp[4]} = {mul_b_reg[4]?{mul_a_reg[7:4], mul_a_reg[3:0]} : 12'h0, 1'b0};
assign {temp[5][7], temp[5]} = {mul_b_reg[5]?{mul_a_reg[7:3], mul_a_reg[2:0]} : 13'h0, 1'b0};
assign {temp[6][7], temp[6]} = {mul_b_reg[6]?{mul_a_reg[7:2], mul_a_reg[1:0]} : 14'h0, 1'b0};
assign {temp[7][7], temp[7]} = {mul_b_reg[7]?{mul_a_reg[7], mul_a_reg[6:0]} : 15'h0, 1'b0};
reg [14:0] sum [6:0];
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum[0] <= 15'd0;
    end else begin
        sum[0] <= temp[0]+temp[1];
    end
end
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum[1] <= 15'd0;
    end else begin
        sum[1] <= temp[2]+temp[3];
    end
end
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum[2] <= 15'd0;
    end else begin
        sum[2] <= temp[4]+temp[5];
    end
end
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum[3] <= 15'd0;
    end else begin
        sum[3] <= temp[6]+temp[7];
    end
end
reg [15:0] mul_out_reg;
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out_reg <= 16'd0;
    end else begin
        mul_out_reg <= sum[0]+sum[1]+sum[2]+sum[3];
    end
end
assign mul_out = mul_en_out?mul_out_reg : 16'd0;
endmodule
